<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Clone</title>
    <style>
        /* --- Global Reset & Variables --- */
        :root {
            --bg-dark: #2c3e50; /* Dark background for desktop/taskbar */
            --fg-light: #ecf0f1; /* Light text color */
            --accent-blue: #4a90e2; /* Ubuntu blue accent */
            --window-bg: #34495e; /* Slightly lighter dark background for windows */
            --border-color: #2c3e50;
            --text-hover: #7f8c8d;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        body, html {
            height: 100%;
            overflow: hidden; /* Desktop fills viewport */
            background-color: var(--bg-dark);
            color: var(--fg-light);
        }

        /* --- Desktop Structure --- */
        #desktop {
            position: relative;
            width: 100%;
            height: calc(100% - 40px); /* Account for taskbar height */
            padding-bottom: 40px; /* Ensure content doesn't hide under taskbar */
        }

        /* --- Taskbar/Dock --- */
        #taskbar {
            position: fixed;
            bottom: 0;
            left: 0;
            width: 100%;
            height: 40px;
            background-color: rgba(30, 45, 65, 0.9); /* Slightly darker/translucent */
            border-top: 1px solid var(--border-color);
            display: flex;
            align-items: center;
            padding: 0 10px;
            z-index: 100;
        }

        .launcher {
            background-color: #34495e;
            color: var(--fg-light);
            border: none;
            padding: 8px 15px;
            margin-right: 10px;
            cursor: pointer;
            transition: background-color 0.2s, transform 0.1s;
            border-radius: 4px;
        }

        .launcher:hover {
            background-color: var(--accent-blue);
            box-shadow: 0 0 8px rgba(74, 144, 226, 0.5);
        }

        /* --- Window Styling (General) --- */
        .window {
            position: absolute;
            background-color: var(--window-bg);
            border: 1px solid #1e303c;
            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.5);
            z-index: 50; /* Below taskbar */
            min-width: 360px;
            min-height: 240px;
            display: none; /* Hidden by default */
            resize: both; /* Allows resizing (though we manage dragging) */
            overflow: hidden;
        }

        .window-header {
            padding: 8px 12px;
            background-color: #2c3e50;
            cursor: move; /* Indicates draggable area */
            display: flex;
            justify-content: space-between;
            align-items: center;
            user-select: none;
        }

        .window-title {
            font-weight: bold;
            color: var(--fg-light);
        }

        .win-close {
            background: none;
            border: none;
            color: #aaa;
            font-size: 18px;
            cursor: pointer;
            padding: 0 5px;
            transition: color 0.2s;
        }

        .win-close:hover {
            color: var(--accent-blue);
        }

        .window-content {
            padding: 15px;
            overflow: auto;
            height: calc(100% - 38px); /* Subtract header height */
            width: 100%;
        }

        /* --- Files App Specifics --- */
        #files-window {
            top: 20px;
            left: 20px;
            width: 600px;
            height: 450px;
        }

        .file-explorer {
            display: flex;
            flex-direction: column;
            gap: 10px;
        }

        #files-path {
            padding: 8px 12px;
            background-color: #3c546b;
            border-bottom: 1px solid var(--border-color);
            font-size: 0.9em;
            user-select: text;
        }

        #files-up {
            padding: 8px 12px;
            background-color: #3c546b;
            cursor: pointer;
            border-bottom: 1px solid var(--border-color);
            display: flex;
            align-items: center;
        }

        #files-up span {
            margin-right: 10px;
        }

        .file-listing {
            padding: 10px 0;
            flex-grow: 1;
            overflow-y: auto;
        }

        .fs-item {
            display: flex;
            align-items: center;
            padding: 8px 12px;
            cursor: pointer;
            transition: background-color 0.1s;
            font-size: 1em;
        }

        .fs-item:hover {
            background-color: #3c546b;
        }

        .fs-item i {
            margin-right: 10px;
            width: 20px; /* Fixed width for icons */
            text-align: center;
        }

        /* --- Notepad App Specifics --- */
        #notepad-window {
            top: 20px;
            left: 350px;
            width: 650px;
            height: 450px;
        }

        .tab-strip {
            display: flex;
            background-color: #2c3e50;
            border-bottom: 1px solid var(--border-color);
            padding-left: 10px;
            height: 38px; /* Must match header height */
        }

        .tab {
            cursor: pointer;
            background-color: #34495e;
            color: var(--fg-light);
            border: 1px solid transparent;
            border-bottom: none;
            padding: 8px 15px;
            margin-right: 2px;
            transition: background-color 0.2s;
            font-size: 0.9em;
        }

        .tab.active {
            background-color: var(--window-bg);
            border-bottom: 1px solid #34495e;
            z-index: 1;
        }

        #editor {
            width: 100%;
            height: calc(100% - 38px); /* Subtract tab strip height */
            padding: 15px;
            border: none;
            resize: none;
            background-color: #2c3e50;
            color: var(--fg-light);
            outline: none;
        }

    </style>
</head>
<body>

    <!-- DESKTOP ROOT -->
    <div id="desktop">
        <!-- Windows will be appended here -->
    </div>

    <!-- TASKBAR/DOCK -->
    <div id="taskbar">
        <button class="launcher" id="open-files">📁 Files</button>
        <button class="launcher" id="open-notepad">📝 Notepad</button>
    </div>


    <!-- ================================================== -->
    <!-- 1. FILES WINDOW (ID: files-window) -->
    <!-- ================================================== -->
    <div id="files-window" class="window">
        <div class="window-header">
            <span class="window-title">File Explorer</span>
            <div>
                <button class="win-close" data-target="#files-window">&times;</button>
            </div>
        </div>
        <div class="window-content file-explorer">
            <!-- Path Display -->
            <div id="files-path">/</div>

            <!-- Up Button -->
            <div id="files-up" style="display: none;">
                <span>&uarr;</span>
                Up Directory
            </div>

            <!-- File Listing Area -->
            <div class="file-listing" id="file-listing">
                <!-- Content populated by JS -->
            </div>
        </div>
    </div>


    <!-- ================================================== -->
    <!-- 2. NOTEPAD WINDOW (ID: notepad-window) -->
    <!-- ================================================== -->
    <div id="notepad-window" class="window">
        <div class="window-header">
            <span class="window-title">Notepad</span>
            <div>
                <button class="win-close" data-target="#notepad-window">&times;</button>
            </div>
        </div>
        <div class="window-content">
            <!-- Tab Strip -->
            <div id="tabs" class="tab-strip">
                <!-- Tabs populated by JS -->
            </div>

            <!-- Editor Area -->
            <textarea id="editor" placeholder="Start typing..."></textarea>
        </div>
    </div>


    <script>
        // ==================================================
        // GLOBAL STATE & UTILITIES
        // ==================================================

        const DESKTOP = document.getElementById('desktop');
        const FILES_WINDOW = document.getElementById('files-window');
        const NOTEPAD_WINDOW = document.getElementById('notepad-window');

        let currentPath = []; // Array representing the path segments (e.g., ['home', 'user'])
        let fileSystemState = {}; // Holds the structure for easy lookup

        // --- File System Definition ---
        // Structure: { name: { type: 'folder'/'file', children: {...} } }
        const FS_DATA = {
            '/': {
                type: 'folder',
                name: '',
                children: {
                    'bin': { type: 'folder', name: 'bin', children: {} },
                    'etc': { type: 'folder', name: 'etc', children: {} },
                    'home': { type: 'folder', name: 'home', children: {
                        'user': { 
                            type: 'folder', 
                            name: 'user', 
                            children: {
                                'Documents': { type: 'folder', name: 'Documents', children: {} },
                                'Downloads': { type: 'folder', name: 'Downloads', children: {} },
                                'Pictures': { type: 'folder', name: 'Pictures', children: {} },
                                'readme.txt': { type: 'file', name: 'readme.txt' }
                            }
                        }
                    },
                    'usr': { type: 'folder', name: 'usr', children: {} },
                    'var': { type: 'folder', name: 'var', children: {} }
                }
            }
        };

        // Initialize the file system state map for easy traversal
        function buildFSMap(node, parent = {}) {
            const map = {};
            for (const key in node.children) {
                const childData = node.children[key];
                map[key] = { ...childData, children: buildFSMap(childData, map) };
            }
            return map;
        }

        fileSystemState = buildFSMap(FS_DATA['/']);


        // ==================================================
        // 1. WINDOW MANAGEMENT (DRAGGING & SHOW/HIDE)
        // ==================================================

        /** Handles showing and hiding any window */
        function toggleWindow(windowId, show = true) {
            const win = document.getElementById(windowId);
            if (!win) return;

            if (show && !win.style.display) {
                // Set initial position/size if needed, then display
                win.style.display = 'block';
                // Ensure it's visible and positioned correctly on load
                setTimeout(() => win.style.opacity = 1, 10);
            } else if (!show && win.style.display) {
                win.style.display = 'none';
                // Optional: Save state or clean up when closing
            }
        }

        /** Makes a window draggable */
        function makeDraggable(element) {
            let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;

            const dragMouseDown = (e) => {
                // Only allow dragging if the click target is the header and not a button
                if (!e.target.closest('.window-header')) return;
                e = e || window;
                pos3 = e.clientX;
                pos4 = e.clientY;
                document.onmouseup = closeDragElement;
                // Call the element's drag function on mouse down
                document.onmousemove = elementDrag;
            };

            const elementDrag = (e) => {
                e = e || window;
                e.preventDefault();
                pos1 = pos3 - e.clientX;
                pos2 = pos4 - e.clientY;
                pos3 = e.clientX;
                pos4 = e.clientY;
                let newTop = element.offsetTop - pos2;
                let newLeft = element.offsetLeft - pos1;

                // Boundary checks (keep within viewport)
                newTop = Math.max(0, Math.min(newTop, window.innerHeight - 50)); // Leave room for taskbar
                newLeft = Math.max(0, Math.min(newLeft, window.innerWidth - element.offsetWidth));

                element.style.top = newTop + "px";
                element.style.left = newLeft + "px";
                element.style.cursor = 'grabbing';
            };

            const closeDragElement = () => {
                document.onmouseup = null;
                document.onmousemove = null;
                element.style.cursor = 'default';
            };

            // Attach listeners to the element itself (the window)
            element.querySelector('.window-header').addEventListener('mousedown', dragMouseDown);
        }


        // ==================================================
        // 2. FILES APP LOGIC
        // ==================================================

        /** Renders the file listing based on currentPath */
        function renderFileListing() {
            const listingContainer = document.getElementById('file-listing');
            if (!listingContainer) return;

            listingContainer.innerHTML = ''; // Clear previous listings

            let currentNode = fileSystemState;
            let pathSegments = [];

            // Traverse the state object to find the current node's children
            for (const segment of currentPath) {
                if (currentNode && currentNode[segment]) {
                    currentNode = currentNode[segment];
                } else {
                    console.error("Invalid path traversal.");
                    return;
                }
            }

            // The actual directory contents are in the 'children' property of the last node
            const children = currentNode ? currentNode.children : {};

            if (Object.keys(children).length === 0) {
                listingContainer.innerHTML = '<p style="padding: 20px; color: #95a5a6;">This directory is empty.</p>';
                return;
            }


            // Sort folders first, then files
            const sortedKeys = Object.keys(children).sort((a, b) => {
                const aIsFolder = children[a].type === 'folder';
                const bIsFolder = children[b].type === 'folder';

                if (aIsFolder && !bIsFolder) return -1; // Folder before File
                if (!aIsFolder && bIsFolder) return 1;  // File after Folder
                return a.localeCompare(b); // Alphabetical sort otherwise
            });


            sortedKeys.forEach(name => {
                const item = children[name];
                const element = document.createElement('div');
                element.className = 'fs-item';
                element.dataset.name = name;

                let icon = '';
                if (item.type === 'folder') {
                    icon = '📁';
                    element.setAttribute('data-type', 'folder');
                    // Double click handler for folders
                    element.ondblclick = () => navigateTo(name); 
                } else {
                    icon = '📄';
                    element.setAttribute('data-type', 'file');
                    // Single click handler for files (optional: view file content)
                    element.onclick = () => alert(`Viewing file: ${name}. Content is static.`);
                }

                element.innerHTML = `<i>${icon}</i><span>${name}</span>`;
                listingContainer.appendChild(element);
            });
        }


        /** Updates the path display and up button visibility */
        function updatePathDisplay() {
            const pathElement = document.getElementById('files-path');
            const upButton = document.getElementById('files-up');

            // Build the absolute path string
            let fullPath = '/';
            if (currentPath.length > 0) {
                fullPath += currentPath.join('/');
            }
            pathElement.textContent = fullPath;

            // Update Up button visibility
            if (currentPath.length > 1) { // If we are deeper than the root
                upButton.style.display = 'flex';
            } else {
                upButton.style.display = 'none';
            }
        }


        /** Navigates into a folder */
        function navigateTo(folderName) {
            const currentFolderNode = fileSystemState;

            // Check if the target exists and is a folder
            if (!currentFolderNode || !currentFolderNode[folderName] || currentFolderNode[folderName].type !== 'folder') {
                console.error(`Cannot navigate to ${folderName}: Not found or not a directory.`);
                return;
            }

            // Update state
            currentPath.push(folderName);

            // Re-render UI
            updatePathDisplay();
            renderFileListing();
        }


        /** Navigates up one level */
        function navigateUp() {
            if (currentPath.length === 0) return; // Should never happen if initialized correctly

            currentPath.pop();

            // Re-render UI
            updatePathDisplay();
            renderFileListing();
        }


        // ==================================================
        // 3. NOTEPAD APP LOGIC (Tabs & Persistence)
        // ==================================================

        const STORAGE_KEY = 'desktop_notepad_tabs';
        let notepadState = {}; // { tabId: { title: string, content: string } }
        let activeTabId = null;


        /** Saves the current state of all tabs to localStorage */
        function saveNotepadState() {
            const tabsData = {};
            document.querySelectorAll('.tab').forEach(tabEl => {
                const tabId = tabEl.dataset.id;
                const content = document.getElementById('editor').value;
                tabsData[tabId] = { 
                    title: tabEl.textContent, 
                    content: content 
                };
            });
            localStorage.setItem(STORAGE_KEY, JSON.stringify(tabsData));
        }

        /** Loads the state from localStorage and rebuilds the UI */
        function loadNotepadState() {
            const savedState = localStorage.getItem(STORAGE_KEY);
            if (!savedState) return;

            notepadState = JSON.parse(savedState);
            renderTabs();
            // Set initial active tab to the first one found in storage
            if (Object.keys(notepadState).length > 0) {
                const firstTabId = Object.keys(notepadState)[0];
                setActiveTab(firstTabId, false); // Load content but don't trigger save/focus cycle
            }
        }

        /** Creates the tab structure and attaches listeners */
        function renderTabs() {
            const tabsContainer = document.getElementById('tabs');
            tabsContainer.innerHTML = '';
            notepadState = {};

            for (let i = 0; i < 3; i++) { // Ensure at least 3 default tabs if storage is empty
                let tabId = `tab-${i}`;
                if (!notepadState[tabId]) {
                    // If we are loading from storage, use the stored IDs. Otherwise, generate new ones.
                    if (Object.keys(notepadState).length < i + 1) {
                        notepadState[tabId] = { title: `Untitled ${i+1}`, content: '' };
                    } else {
                         // Use existing keys if available
                         const existingKeys = Object.keys(notepadState);
                         if (existingKeys.length > i) {
                            tabId = existingKeys[i];
                        } else {
                             break; // Stop if we run out of stored tabs
                        }
                    }
                }

                // Create tab element
                const tabEl = document.createElement('div');
                tabEl.className = 'tab';
                tabEl.dataset.id = tabId;
                tabEl.textContent = notepadState[tabId].title;
                tabEl.onclick = () => setActiveTab(tabId);
                tabsContainer.appendChild(tabEl);

                // Initialize state if new
                if (!notepadState[tabId]) {
                    notepadState[tabId] = { title: `Untitled ${i+1}`, content: '' };
                }
            }
        }


        /** Switches the active tab and updates the editor */
        function setActiveTab(tabId, shouldSave = true) {
            if (activeTabId === tabId && !shouldSave) return;

            // 1. Save current content if switching away
            if (activeTabId && shouldSave) {
                const currentContent = document.getElementById('editor').value;
                notepadState[activeTabId].content = currentContent;
                saveNotepadState();
            }

            // 2. Update active class visuals
            document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
            const newActiveTabEl = document.querySelector(`.tab[data-id="${tabId}"]`);
            if (newActiveTabEl) {
                newActiveTabEl.classList.add('active');
            }

            // 3. Load content into editor
            const tabData = notepadState[tabId];
            document.getElementById('editor').value = tabData ? tabData.content : '';
            activeTabId = tabId;
        }


        /** Handles the creation of a new tab */
        function createNewTab() {
            let newIndex = 1;
            while (notepadState[`tab-${newIndex}`]) {
                newIndex++;
            }
            const newTabId = `tab-${newIndex}`;

            // Update state and UI
            notepadState[newTabId] = { title: 'Untitled', content: '' };

            const tabEl = document.createElement('div');
            tabEl.className = 'tab active'; // Make it active immediately
            tabEl.dataset.id = newTabId;
            tabEl.textContent = 'Untitled';
            tabEl.onclick = () => setActiveTab(newTabId);

            document.getElementById('tabs').appendChild(tabEl);
            activeTabId = newTabId;
        }


        // ==================================================
        // 4. INITIALIZATION & EVENT LISTENERS
        // ==================================================

        function initialize() {
            // --- A. Window Setup and Interactivity ---
            makeDraggable(FILES_WINDOW);
            makeDraggable(NOTEPAD_WINDOW);

            // Close button handlers (Delegation)
            document.querySelectorAll('.win-close').forEach(button => {
                button.onclick = function() {
                    const targetId = this.dataset.target;
                    if (targetId === '#files-window') {
                        toggleWindow('files-window', false);
                    } else if (targetId === '#notepad-window') {
                        // Save state before closing Notepad
                        saveNotepadState(); 
                        toggleWindow('notepad-window', false);
                    }
                };
            });

            // Launcher button handlers
            document.getElementById('open-files').onclick = () => toggleWindow('files-window', true);
            document.getElementById('open-notepad').onclick = () => {
                // Ensure Notepad is initialized before opening
                if (Object.keys(notepadState).length === 0) {
                    renderTabs(); // Initial render if nothing was loaded
                }
                toggleWindow('notepad-window', true);
            };

            // --- B. File Explorer Setup ---
            updatePathDisplay();
            renderFileListing();


            // --- C. Notepad Event Listeners ---
            const editor = document.getElementById('editor');

            // 1. Typing/Input: Save content on input event (debounced or throttled in real life, but simple save here)
            editor.addEventListener('input', () => {
                if (activeTabId) {
                    notepadState[activeTabId].content = editor.value;
                    // We don't call saveNotepadState() on every keystroke to prevent performance hit, 
                    // but rely on the explicit 'blur' or close event for persistence.
                }
            });

            // 2. Tab Switching: Click handler is already set up in renderTabs/setActiveTab

            // 3. New Tab Button (We simulate this by adding a button listener)
            const tabsContainer = document.getElementById('tabs');
            if (!document.getElementById('new-tab')) {
                 // Add a visible "New" tab button next to the strip for usability, though not strictly required by ID contract
                const newTabButton = document.createElement('button');
                newTabButton.className = 'launcher';
                newTabButton.style.marginLeft = '5px';
                newTabButton.textContent = '+ New Tab';
                newTabButton.onclick = createNewTab;
                tabsContainer.parentNode.appendChild(newTabButton); // Append to the parent of #tabs

            } else {
                 document.getElementById('new-tab').onclick = createNewTab;
            }


            // --- D. Persistence Handlers (Window Focus/Blur) ---
            window.addEventListener('beforeunload', saveNotepadState);

            // Load state after all setup is complete
            loadNotepadState(); 
        }

        // Run initialization when the DOM is fully loaded
        document.addEventListener('DOMContentLoaded', initialize);

    </script>
</body>
</html>
